import React, { useEffect, useState } from "react";

function Orders({ apiBase, getStatusClass }) {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [updatingId, setUpdatingId] = useState(null);

  useEffect(() => {
    loadOrders();
    const timer = setInterval(loadOrders, 5000);
    return () => clearInterval(timer);
  }, []);

  async function loadOrders() {
    try {
      const response = await fetch(`${apiBase}/orders`);
      const data = await response.json();
      setOrders(Array.isArray(data) ? data : []);
    } catch (error) {
      setOrders([]);
    } finally {
      setLoading(false);
    }
  }

  async function markCompleted(order) {
    try {
      setUpdatingId(order.id);

      const payload = {
        foodName: order.foodName,
        quantity: order.quantity,
        totalPrice: order.totalPrice,
        status: "Completed",
        customerName: order.customerName,
        paymentMethod: order.paymentMethod,
        orderType: order.orderType,
        pickupSlot: order.pickupSlot,
        notes: order.notes,
        waitingTime: order.waitingTime
      };

      const response = await fetch(`${apiBase}/orders/${order.id}`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(payload)
      });

      if (!response.ok) {
        throw new Error("Failed to update order");
      }

      loadOrders();
    } catch (error) {
      console.error("Failed to mark order as completed");
    } finally {
      setUpdatingId(null);
    }
  }

  return (
    <section className="section-gap">
      <div className="content-card">
        <div className="section-title-row">
          <div>
            <h2>Live Orders</h2>
            <p>Track placed orders and see their latest preparation status.</p>
          </div>
        </div>

        {loading ? (
          <div className="empty-box">Loading orders...</div>
        ) : orders.length === 0 ? (
          <div className="empty-box">No orders placed yet.</div>
        ) : (
          <div className="orders-grid">
            {orders.map((order) => (
              <div className="order-card" key={order.id}>
                <div className="order-card-top">
                  <div>
                    <h3>{order.foodName}</h3>
                    <p><strong>Customer:</strong> {order.customerName}</p>
                    <p><strong>Quantity:</strong> {order.quantity}</p>
                    <p><strong>Total:</strong> ₹{order.totalPrice}</p>
                    <p><strong>Payment:</strong> {order.paymentMethod}</p>
                    <p><strong>Type:</strong> {order.orderType}</p>
                    <p><strong>Pickup:</strong> {order.pickupSlot}</p>
                    <p><strong>Waiting Time:</strong> {order.waitingTime} mins</p>
                    {order.notes ? <p><strong>Notes:</strong> {order.notes}</p> : null}
                  </div>

                  <span className={getStatusClass(order.status)}>
                    {order.status}
                  </span>
                </div>

                <div className="action-row wrap-row">
                  <button
                    className="primary-btn"
                    onClick={() => markCompleted(order)}
                    disabled={
                      updatingId === order.id ||
                      String(order.status).toLowerCase() === "completed"
                    }
                  >
                    {String(order.status).toLowerCase() === "completed"
                      ? "Completed"
                      : updatingId === order.id
                      ? "Updating..."
                      : "Mark Completed"}
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

export default Orders;
